```javascript
function stripAuthFromUrl(url) {
  const authIndex = url.indexOf('@');
  if (authIndex !== -1) {
    const auth = url.substring(0, authIndex);
    const rest = url.substring(authIndex + 1);
    const colonIndex = auth.indexOf(':');
    if (colonIndex !== -1) {
      return rest;
    } else {
      return url;
    }
  } else {
    return url;
  }
}

